properties.scriptContent:
set -euo pipefail
# Parse named arguments
while [ $# -gt 0 ]; do case "$1" in 
--targetAcr) TARGET_ACR="$2"; shift 2;; 
--targetImageName) TARGET_IMAGE_NAME="$2"; shift 2;; 
--targetImageTag) TARGET_IMAGE_TAG="$2"; shift 2;; 
--sourceAcr) SOURCE_ACR="$2"; shift 2;; 
--sourceImageName) SOURCE_IMAGE_NAME="$2"; shift 2;; 
--sourceImageTag) SOURCE_IMAGE_TAG="$2"; shift 2;; 
--sourceSubscription) SOURCE_SUB="$2"; shift 2;; 
--sourceResourceGroup) SOURCE_RG="$2"; shift 2;; 
--sourceUsername) SOURCE_USERNAME="$2"; shift 2;; 
--sourcePassword) SOURCE_PASSWORD="$2"; shift 2;; 
--targetSubscription) TARGET_SUB="$2"; shift 2;; 
*) shift ;; esac; done
# Login with the assigned identity
az login --identity >/dev/null 2>&1
# Build the import command including the target subscription
IMPORT_CMD=(az acr import --subscription "$TARGET_SUB" --name "$TARGET_ACR" --source "${SOURCE_ACR}.azurecr.io/${SOURCE_IMAGE_NAME}:${SOURCE_IMAGE_TAG}" --image "${TARGET_IMAGE_NAME}:${TARGET_IMAGE_TAG}" --source-subscription "$SOURCE_SUB")
if [ -n "$SOURCE_RG" ]; then
  IMPORT_CMD+=(--source-resource-group "$SOURCE_RG")
fi
if [ -n "$SOURCE_USERNAME" ] && [ -n "$SOURCE_PASSWORD" ]; then
  IMPORT_CMD+=(--username "$SOURCE_USERNAME" --password "$SOURCE_PASSWORD")
fi
# Execute the import
"${IMPORT_CMD[@]}"
